query:
UPDATE orders SET totalQuantity = (
  SELECT COALESCE(SUM(CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(mealContent, ' x', -1), ',', 1) AS UNSIGNED)), 0)
  FROM (SELECT mealContent) AS temp
  WHERE FIND_IN_SET(SUBSTRING_INDEX(SUBSTRING_INDEX(mealContent, ' x', -1), ',', 1), mealContent)
) WHERE totalQuantity = 0;

